"""This is "Prompt Engineering" at the code level.
We limit the AI's imagination and force it to sort the text into the fields we have defined so that this data can be immediately saved in Excel.

"""

sns.set_theme(style="whitegrid")

# Define the output structure using Pydantic.
class AccidentAnalysis(BaseModel):
    typ_nehody: str = Field(
        description="Typ dopravní nehody (např. Srážka jedoucích vozidel, Havárie, Srážka s chodcem...)"
    )
    smer_stretu: str = Field(
        description="Předstřetová konfigurace účastníků nehody / směr střetu (např. Čelní, Boční, Zezadu, Nepřehledná situace)"
    )
    pritomnost_smyku: bool = Field(
        description="Byl u některého z vozidel detekován smyk nebo zanošení? (True = Ano, False = Ne)"
    )
    prejeti_do_protismeru: bool = Field(
        description="Přejetí do protisměru některým z vozidel? (True = Ano, False = Ne)"
    )
    ucast_motocyklisty_chodce_cyklisty: List[str] = Field(
        description="Účast zranitelných účastníků. Vyberte z: 'motocyklista', 'chodec', 'cyklista'. Pokud nikdo, nechte prázdné."
    )
    faktory_prispivajici_k_nehode: List[str] = Field(
        description="Faktory přispívající ke vzniku nehody (příčiny nehod)"
    )
    jina_relevantni_charakteristika: Optional[str] = Field(
        description="Případně jinou relevantní charakteristiku (např. alkohol, specifické počasí, mikrospánek)"
    )

