"""1. Data Loading & Safety Checks: The function analyze_accidents dynamically reads either a .csv or .xlsx file using Pandas. It immediately checks if your required columns (fall for ID, and ighergang for the text) exist to prevent crashes.

2. Processing in Batches (Testing Mode): To save API limits and time, it restricts the analysis to a small subset using df.head(sample_limit) (set to 10 rows for testing).

3. Setting the AI Persona: It defines a system_instruction in Czech, telling the AI to act as a traffic accident expert. This ensures the model understands the specific domain and language context.

4. The AI Loop & JSON Enforcement: It loops through each row and sends the text to gemini-2.5-flash. Crucially, it uses the configuration response_schema=AccidentAnalysis and response_mime_type="application/json". This forces the AI to reply strictly in my Pydantic structure.

5. Low Temperature for Accuracy: It sets temperature=0.1. In AI, temperature controls creativity. A low value ensures the model gives highly analytical, consistent, and factual answers rather than making things up.

6. Data Assembly: Once the AI returns the JSON, Pydantic safely parses it. The script then merges this AI analysis with the original ID (fall_id) and description, compiles it into a new Pandas DataFrame, and neatly reorders the columns for final export.
"""

def analyze_accidents(file_path: str, sample_limit: int = 20):
    client = genai.Client()
    try:
        if file_path.endswith('.csv'):
            df = pd.read_csv(file_path)
        else:
            df = pd.read_excel(file_path)
    except Exception as e:
        print(f"Error loading file: {e}")
        return None
    # Check  existence
    if 'fall' not in df.columns or 'ighergang' not in df.columns:
        print(f" WARNING: Could not find 'fall' and 'ighergang' columns. Found: {df.columns.tolist()}")
        return None
    # Limit rows for testing purposes
    df_subset = df.head(sample_limit)
    analyzed_data = []
    system_instruction = (
        "Jste expert na analýzu dopravních nehod v ČR. Vaším úkolem je analyzovat "
        "textový popis nehody a extrahovat přesné vlastnosti do JSON struktury."
    )
    print(f"Starting analysis for {len(df_subset)} records...")
    for index, row in df_subset.iterrows():
        acc_id = row['fall']
        description = str(row['ighergang'])
        # Skip empty
        if pd.isna(row['ighergang']) or description.strip() == "":
            continue
        try:
            # Generate structured JSON via GemApi
            response = client.models.generate_content(
                model='gemini-2.5-flash',
                contents=f"Analyzuj následující popis nehody:\n\n{description}",
                config=types.GenerateContentConfig(
                    system_instruction=system_instruction,
                    response_mime_type="application/json",
                    response_schema=AccidentAnalysis,
                    temperature=0.1, # Low temperature for analytical consistency
                ),
            )
            # Parse the response safely
            result = AccidentAnalysis.model_validate_json(response.text)
            result_dict = result.model_dump()
            # Append to the result
            result_dict['fall_id'] = acc_id
            result_dict['text_popisu'] = description
            analyzed_data.append(result_dict)
            print(f"Processed ID: {acc_id}")
        except Exception as e:
            print(f"Error processing ID {acc_id}: {e}")

    report_df = pd.DataFrame(analyzed_data)
    # Reorder columns
    cols = ['fall_id', 'text_popisu', 'typ_nehody', 'smer_stretu', 'pritomnost_smyku',
            'prejeti_do_protismeru', 'ucast_motocyklisty_chodce_cyklisty',
            'faktory_prispivajici_k_nehode', 'jina_relevantni_charakteristika']
    # Filter only columns that actually exist in the dataframe to prevent errors
    report_df = report_df[[c for c in cols if c in report_df.columns]]
    print("\n✅ Analysis complete!")
    return report_df
# Run the pipeline (processing 10 rows for initial testing)
report_df = analyze_accidents(input_filename, sample_limit=10)

if report_df is not None:
    display(report_df.head())

