if report_df is not None:
    excel_df = report_df.copy()
    # Convert lists to comma-separated
    excel_df['ucast_motocyklisty_chodce_cyklisty'] = excel_df['ucast_motocyklisty_chodce_cyklisty'].apply(
        lambda x: ", ".join(x) if isinstance(x, list) else str(x)
    )
    excel_df['faktory_prispivajici_k_nehode'] = excel_df['faktory_prispivajici_k_nehode'].apply(
        lambda x: ", ".join(x) if isinstance(x, list) else str(x)
    )
    output_excel_name = "analyza_nehod_vysledek.xlsx"
    excel_df.to_excel(output_excel_name, index=False, sheet_name='Analýza')
    print(f"Data saved. Downloading {output_excel_name}...")
    files.download(output_excel_name)

